import React, { useState, useEffect } from 'react';
import { useSlides } from '../contexts/SlideContext';
import { useToast } from '../contexts/ToastContext';
import { ImageSlide, SLIDE_TYPES } from '../types';
import useDemoImages from '../hooks/useDemoImages';

const BACKEND_URL = "http://localhost:5000";

/**
 * Admin Page Component
 */
const getApiUrl = () => {
    // Use proxy in dev, or absolute in prod
    if (process.env.NODE_ENV === 'development') {
        return `${BACKEND_URL}/api/upload`;
    }
    return '/api/upload';
};

const AdminPage: React.FC = () => {
    const { slides, activeSlide, setActiveSlide, addSlide, updateSlide, deleteSlide } = useSlides();
    const { addToast } = useToast();
    const [isEditing, setIsEditing] = useState(false);
    const [pendingImageFile, setPendingImageFile] = useState<File | null>(null);
    const [imagePreviewUrl, setImagePreviewUrl] = useState<string>("");

    // Use demo images instead of hardcoded ones
    const demoImages = useDemoImages(4);

    // Form state
    const [slideName, setSlideName] = useState('');
    const [slideCaption, setSlideCaption] = useState('');
    const [slideDuration, setSlideDuration] = useState(5);
    const [slideActive, setSlideActive] = useState(true);

    /**
     * Handle file input change
     */
    const handleFileInput = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        setPendingImageFile(file || null);
        if (file) {
            const formData = new FormData();
            formData.append('file', file);
            try {
                const res = await fetch(getApiUrl(), { method: 'POST', body: formData });
                const data = await res.json();
                if (data.url) {
                    // Always use absolute URL for preview and slide
                    const imageUrl = data.url.startsWith('http') ? data.url : `${BACKEND_URL}${data.url}`;
                    setImagePreviewUrl(imageUrl);
                } else {
                    setImagePreviewUrl("");
                    addToast('Upload failed', 'error');
                }
            } catch (err) {
                setImagePreviewUrl("");
                addToast('Upload failed', 'error');
            }
        } else {
            setImagePreviewUrl("");
        }
    };

    /**
     * Create a new slide
     */
    const createNewSlide = () => {
        const newSlide: ImageSlide = {
            id: `slide-${Date.now()}-${Math.floor(Math.random() * 1000)}`,
            name: "New Image Slide",
            type: SLIDE_TYPES.IMAGE,
            dataSource: "manual",
            data: {
                imageUrl: "",
                caption: ""
            },
            duration: 5,
            active: true
        };

        setActiveSlide(newSlide);
        setIsEditing(false);

        // Reset form fields
        setSlideName(newSlide.name);
        setSlideCaption(newSlide.data.caption || '');
        setSlideDuration(newSlide.duration);
        setSlideActive(newSlide.active);

        // Show edit form
        document.getElementById("noSlideSelected")?.classList.add("hidden");
        document.getElementById("slideEditForm")?.classList.remove("hidden");
    };

    /**
     * Edit an existing slide
     */
    const editSlide = (slideId: string) => {
        const slide = slides.find(s => s.id === slideId);
        if (!slide) return;

        // Set the active slide
        setActiveSlide(slide);
        setIsEditing(true);

        // Populate form fields
        setSlideName(slide.name);
        setSlideCaption((slide as ImageSlide).data.caption || '');
        setSlideDuration(slide.duration);
        setSlideActive(slide.active);

        // Set image URL if we have one
        const imageUrl = (slide as ImageSlide).data.imageUrl;
        setImagePreviewUrl(imageUrl);

        // Show edit form
        document.getElementById("noSlideSelected")?.classList.add("hidden");
        document.getElementById("slideEditForm")?.classList.remove("hidden");
    };

    /**
     * Save the current slide
     */
    const saveSlide = (e: React.FormEvent) => {
        e.preventDefault();
        if (!activeSlide) return;
        let imageUrl = imagePreviewUrl;
        if (!imageUrl) {
            addToast("Please upload an image file", "error");
            return;
        }
        const updatedSlide: ImageSlide = {
            ...activeSlide as ImageSlide,
            name: slideName,
            data: {
                imageUrl,
                caption: slideCaption
            },
            duration: slideDuration,
            active: slideActive
        };
        if (isEditing) {
            updateSlide(updatedSlide);
            addToast("Slide updated successfully");
        } else {
            addSlide(updatedSlide);
            addToast("New slide created successfully");
        }
        hideEditForm();
    };

    /**
     * Delete a slide
     */
    const handleDeleteSlide = (slideId: string) => {
        if (window.confirm("Are you sure you want to delete this slide?")) {
            deleteSlide(slideId);
            addToast("Slide deleted successfully", "info");

            // Hide edit form if the deleted slide was being edited
            if (activeSlide && activeSlide.id === slideId) {
                hideEditForm();
            }
        }
    };

    /**
     * Hide the edit form
     */
    const hideEditForm = () => {
        document.getElementById("slideEditForm")?.classList.add("hidden");
        document.getElementById("noSlideSelected")?.classList.remove("hidden");

        // Reset state
        setActiveSlide(null);
        setImagePreviewUrl("");

        // Reset form inputs
        const selector = document.getElementById("imageSelector") as HTMLSelectElement;
        if (selector) selector.selectedIndex = 0;
    };

    return (
        <>
            <h1 className="text-3xl font-bold text-center mb-8">LED Display Admin</h1>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                {/* Slide List (Left) */}
                <div className="lg:col-span-1">
                    <div className="bg-base-100 rounded-lg shadow-lg p-4">
                        <div className="flex justify-between items-center mb-4">
                            <h2 className="text-xl font-bold">Image Slides</h2>
                            <button
                                onClick={createNewSlide}
                                className="btn btn-primary btn-sm"
                            >
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 mr-1" fill="none" viewBox="0 0 24 24"
                                    stroke="currentColor">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2"
                                        d="M12 4v16m8-8H4" />
                                </svg>
                                New Slide
                            </button>
                        </div>

                        <div className="space-y-4 mt-4">
                            {slides.length === 0 ? (
                                <div className="alert alert-info">
                                    <div>
                                        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" className="stroke-current flex-shrink-0 w-6 h-6">
                                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path>
                                        </svg>
                                        <span>No image slides found. Create a new slide to get started.</span>
                                    </div>
                                </div>
                            ) : (
                                slides.map(slide => {
                                    // Only handle image slides
                                    if (slide.type !== SLIDE_TYPES.IMAGE) return null;

                                    const imageSlide = slide as ImageSlide;
                                    const imageUrl = imageSlide.data.imageUrl || "";
                                    const imageName = imageUrl.split('/').pop() || "No image";

                                    // Status badge
                                    const statusBadge = slide.active
                                        ? <div className="badge badge-success">Active</div>
                                        : <div className="badge badge-ghost">Inactive</div>;

                                    return (
                                        <div key={slide.id} className="card bg-base-100 shadow-md hover:shadow-lg transition-shadow">
                                            {imageUrl ? (
                                                <img
                                                    src={imageUrl}
                                                    alt={slide.name}
                                                    className="h-24 w-full object-cover rounded-t-lg"
                                                    onError={(e) => {
                                                        const target = e.target as HTMLImageElement;
                                                        target.onerror = null;
                                                        target.src = 'data:image/svg+xml;base64,';
                                                        target.classList.add('bg-slate-100');
                                                        target.classList.add('p-4');
                                                    }}
                                                />
                                            ) : (
                                                <div className="h-24 bg-base-200 flex items-center justify-center rounded-t-lg">
                                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                                                    </svg>
                                                </div>
                                            )}

                                            <div className="card-body p-4">
                                                <div className="flex justify-between items-start">
                                                    <h3 className="font-medium text-sm line-clamp-1">{slide.name}</h3>
                                                    {statusBadge}
                                                </div>
                                                <p className="text-xs text-slate-500 line-clamp-1">{imageSlide.data.caption || "No caption"}</p>
                                                <p className="text-xs text-slate-400 line-clamp-1">{imageName}</p>
                                                <div className="card-actions justify-end mt-2">
                                                    <button
                                                        className="btn btn-xs btn-primary"
                                                        onClick={() => editSlide(slide.id)}
                                                    >
                                                        Edit
                                                    </button>
                                                    <button
                                                        className="btn btn-xs btn-outline btn-error"
                                                        onClick={() => handleDeleteSlide(slide.id)}
                                                    >
                                                        Delete
                                                    </button>
                                                </div>
                                            </div>
                                        </div>
                                    );
                                })
                            )}
                        </div>
                    </div>
                </div>

                {/* Slide Editor (Right) */}
                <div className="lg:col-span-2">
                    <div className="bg-base-100 rounded-lg shadow-lg p-6">
                        {/* Default view when no slide is selected */}
                        <div id="noSlideSelected" className="text-center py-12">
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16 mx-auto text-slate-300 mb-4"
                                fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2"
                                    d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                            </svg>
                            <h3 className="text-xl font-semibold mb-2">No Slide Selected</h3>
                            <p className="text-slate-500">Select a slide from the list or create a new one to edit.</p>
                        </div>

                        {/* Slide edit form - hidden by default */}
                        <form id="slideEditForm" className="space-y-6" onSubmit={saveSlide}>
                            <div className="form-control">
                                <label className="label" htmlFor="slideName">
                                    <span className="label-text font-medium">Slide Name</span>
                                </label>
                                <input
                                    type="text"
                                    id="slideName"
                                    className="input input-bordered w-full"
                                    placeholder="Enter a name for this slide"
                                    value={slideName}
                                    onChange={(e) => setSlideName(e.target.value)}
                                    required
                                />
                            </div>

                            <div className="form-control">
                                <label className="label" htmlFor="slideImageFile">
                                    <span className="label-text font-medium">Upload Image</span>
                                </label>
                                <input
                                    type="file"
                                    id="slideImageFile"
                                    accept="image/*"
                                    className="input input-bordered w-full"
                                    onChange={handleFileInput}
                                />
                                <div className="text-xs text-slate-500 mt-1">
                                    Choose an image file to upload for this slide
                                </div>
                            </div>

                            <div className="form-control">
                                <label className="label" htmlFor="slideCaption">
                                    <span className="label-text font-medium">Caption (Optional)</span>
                                </label>
                                <input
                                    type="text"
                                    id="slideCaption"
                                    className="input input-bordered w-full"
                                    placeholder="Image caption or description"
                                    value={slideCaption}
                                    onChange={(e) => setSlideCaption(e.target.value)}
                                />
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <div className="form-control">
                                    <label className="label" htmlFor="slideDuration">
                                        <span className="label-text font-medium">Duration (seconds)</span>
                                    </label>
                                    <input
                                        type="number"
                                        id="slideDuration"
                                        className="input input-bordered w-full"
                                        min="1"
                                        max="60"
                                        value={slideDuration}
                                        onChange={(e) => setSlideDuration(parseInt(e.target.value))}
                                        required
                                    />
                                </div>

                                <div className="form-control">
                                    <label className="label" htmlFor="slideActive">
                                        <span className="label-text font-medium">Status</span>
                                    </label>
                                    <div className="input input-bordered flex items-center h-12">
                                        <input
                                            type="checkbox"
                                            id="slideActive"
                                            className="toggle toggle-primary"
                                            checked={slideActive}
                                            onChange={(e) => setSlideActive(e.target.checked)}
                                        />
                                        <span className="ml-2">Active</span>
                                    </div>
                                </div>
                            </div>

                            <div className="form-control">
                                <label className="label">
                                    <span className="label-text font-medium">Image Preview</span>
                                </label>
                                <div className="bg-base-200 rounded-lg flex items-center justify-center min-h-[200px] overflow-hidden">
                                    {imagePreviewUrl ? (
                                        <img
                                            src={imagePreviewUrl}
                                            alt="Slide preview"
                                            className="max-w-full max-h-[300px]"
                                        />
                                    ) : (
                                        <span className="text-slate-400">Upload an image to preview</span>
                                    )}
                                </div>
                            </div>

                            <div className="flex justify-end space-x-2 pt-4">
                                <button
                                    type="button"
                                    className="btn btn-outline"
                                    onClick={hideEditForm}
                                >
                                    Cancel
                                </button>
                                <button type="submit" className="btn btn-primary">Save Slide</button>
                            </div>
                        </form>
                    </div>
                </div>
            </div>
        </>
    );
};

export default AdminPage;
